scwin.onpageload = async function() {
    const codeOptions = [
        // { grpCd : "FS261", compID : "acb_copCoConfirmClsCd"},    // 업체확인구분
        { grpCd : "FS262", compID : "acb_pchsAdmitClsCd"},     // 업체확인구분
        { grpCd : "SD113", compID : "acb_odrKndCd"}     // 업체확인구분
    ];
    $c.data.setCommonCode(codeOptions, scwin.comboCallBack);

	scwin.lobranCd = $c.data.getMemInfo("lobranCd");
	if (!await $c.gus.cfIsNull(scwin.lobranCd)) {
	    scwin.lobranCd = scwin.lobranCd.substring(0, 2) + "2";
	} else {
	    scwin.lobranCd = "";
	}

	scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
	scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
	scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + $c.date.getLastDateOfMonth((scwin.vCurDate.substring(0,6)));  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)
    scwin.pchsSelAmt = 0; 	
    scwin.pchsSelCount = 0; 	
    scwin.pchsDcScSelAmt = 0; 

};

